'use client';

import { useState, useEffect, useCallback } from 'react';

import {
  Combobox,
  ComboboxContent,
  ComboboxInput,
  ComboboxItem,
  ComboboxList,
  ComboboxEmpty,
  ComboboxGroup,
  ComboboxLabel
} from '@/components/ui/combobox';
import { useDebounce } from '@/hooks/use-debounce';
import { Search, X, Clock, Loader2, TrendingUp } from 'lucide-react';

import { cn } from '@/lib/utils';

export interface SearchOption {
  id: string;
  title: string;
  description?: string;
  category?: string;
}

export interface SearchProps {
  onSearch?: (query: string) => Promise<SearchOption[]>;
  trendingSearches?: SearchOption[];
  onSelect?: (item: SearchOption) => void;
  placeholder?: string;
  className?: string;
  maxRecentSearches?: number;
  showRecentSearches?: boolean;
  showTrendingSearches?: boolean;
}

function getSearchDisplayValue(item: SearchOption) {
  return item.description ? `${item.title} - ${item.description}` : item.title;
}

const mockSearch = async (query: string): Promise<SearchOption[]> => {
  await new Promise((resolve) => setTimeout(resolve, 500));

  const mockData: SearchOption[] = [
    {
      id: '1',
      title: 'React Documentation',
      description: 'Official React docs and tutorials',
      category: 'Documentation'
    },
    {
      id: '2',
      title: 'TypeScript Handbook',
      description: 'Learn TypeScript from scratch',
      category: 'Documentation'
    },
    {
      id: '3',
      title: 'Next.js Examples',
      description: 'Production-ready Next.js examples',
      category: 'Examples'
    },
    {
      id: '4',
      title: 'Tailwind CSS',
      description: 'Utility-first CSS framework',
      category: 'Styling'
    },
    {
      id: '5',
      title: 'Vite Configuration',
      description: 'Build tool configuration guide',
      category: 'Tools'
    },
    {
      id: '6',
      title: 'React Hooks',
      description: 'Complete guide to React Hooks',
      category: 'React'
    },
    {
      id: '7',
      title: 'JavaScript ES6+',
      description: 'Modern JavaScript features',
      category: 'JavaScript'
    },
    {
      id: '8',
      title: 'Node.js Best Practices',
      description: 'Server-side JavaScript guide',
      category: 'Node.js'
    }
  ];

  if (!query.trim()) return [];

  return mockData.filter(
    (item) =>
      item.title.toLowerCase().includes(query.toLowerCase()) ||
      item.description?.toLowerCase().includes(query.toLowerCase()) ||
      item.category?.toLowerCase().includes(query.toLowerCase())
  );
};
function SearchItem({ item }: { item: SearchOption }) {
  return (
    <div className="flex flex-col">
      <div className="font-medium">{item.title}</div>
      {item.description && (
        <div className="text-muted-foreground text-sm">{item.description}</div>
      )}
      {item.category && (
        <div className="text-muted-foreground mt-1 text-xs">
          {item.category}
        </div>
      )}
    </div>
  );
}

export function SearchComponent({
  onSearch = mockSearch,
  trendingSearches = [],
  onSelect,
  placeholder = 'Search documentation, examples, and more...',
  className,
  maxRecentSearches = 5,
  showRecentSearches = true,
  showTrendingSearches = true
}: SearchProps) {
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<SearchOption[]>([]);
  const [loading, setLoading] = useState(false);
  const [recentSearches, setRecentSearches] = useState<string[]>([]);
  const debouncedQuery = useDebounce(query, 300);

  useEffect(() => {
    const saved = localStorage.getItem('recent-searches');
    if (saved) {
      try {
        setRecentSearches(JSON.parse(saved));
      } catch (e) {
        console.error('Failed to load recent searches:', e);
      }
    }
  }, []);

  const saveRecentSearch = useCallback(
    (searchQuery: string) => {
      if (!searchQuery.trim()) return;

      setRecentSearches((prev) => {
        const updated = [
          searchQuery,
          ...prev.filter((s) => s !== searchQuery)
        ].slice(0, maxRecentSearches);
        localStorage.setItem('recent-searches', JSON.stringify(updated));
        return updated;
      });
    },
    [maxRecentSearches]
  );

  useEffect(() => {
    if (debouncedQuery.trim()) {
      const performSearch = async () => {
        setLoading(true);
        try {
          const searchResults = await onSearch(debouncedQuery);
          setResults(searchResults);
        } catch (error) {
          console.error('Search failed:', error);
          setResults([]);
        } finally {
          setLoading(false);
        }
      };

      performSearch();
    } else {
      setResults([]);
      setLoading(false);
    }
  }, [debouncedQuery, onSearch]);

  const handleSelect = useCallback(
    (item: SearchOption) => {
      const displayValue = getSearchDisplayValue(item);
      saveRecentSearch(displayValue);
      onSelect?.(item);
      setOpen(false);
      setQuery(displayValue);
    },
    [onSelect, saveRecentSearch]
  );

  const clearRecentSearches = useCallback(() => {
    setRecentSearches([]);
    localStorage.removeItem('recent-searches');
  }, []);

  const removeRecentSearch = useCallback(
    (searchToRemove: string, e: React.MouseEvent) => {
      e.stopPropagation();
      setRecentSearches((prev) => {
        const updated = prev.filter((s) => s !== searchToRemove);
        localStorage.setItem('recent-searches', JSON.stringify(updated));
        return updated;
      });
    },
    []
  );

  const showTrending = showTrendingSearches && !query.trim() && open;
  const showRecent =
    showRecentSearches && !query.trim() && recentSearches.length > 0 && open;
  const showResults = query.trim() && (results.length > 0 || loading);

  return (
    <div className={cn('relative w-full max-w-lg', className)}>
      <Combobox
        open={open}
        onOpenChange={setOpen}
        inputValue={query}
        onInputValueChange={setQuery}
        onValueChange={(value: unknown) => {
          const stringValue = String(value);

          if (recentSearches.includes(stringValue)) {
            setQuery(stringValue);
            saveRecentSearch(stringValue);
            setOpen(false);
            return;
          }

          const allItems = [...trendingSearches, ...results];
          const selectedItem = allItems.find(
            (item) => getSearchDisplayValue(item) === stringValue
          );
          if (selectedItem) {
            handleSelect(selectedItem);
          }
        }}
      >
        <ComboboxInput
          placeholder={placeholder}
          className="w-full"
          showTrigger={false}
          showClear={false}
        />

        <ComboboxContent>
          <ComboboxList>
            {showTrending && (
              <ComboboxGroup>
                <ComboboxLabel className="flex items-center gap-2">
                  <TrendingUp className="text-muted-foreground h-4 w-4" />
                  Trending Searches
                </ComboboxLabel>
                {trendingSearches.map((item) => (
                  <ComboboxItem
                    key={item.id}
                    value={getSearchDisplayValue(item)}
                  >
                    <SearchItem item={item} />
                  </ComboboxItem>
                ))}
              </ComboboxGroup>
            )}

            {showRecent && (
              <ComboboxGroup>
                <ComboboxLabel className="flex items-center justify-between">
                  <span className="flex items-center gap-2">
                    <Clock className="text-muted-foreground h-4 w-4" />
                    Recent Searches
                  </span>
                  <button
                    onClick={clearRecentSearches}
                    className="muted-foreground hover:text-foreground text-xs"
                  >
                    Clear all
                  </button>
                </ComboboxLabel>
                {recentSearches.map((search, index) => (
                  <ComboboxItem
                    key={`recent-${index}`}
                    value={search}
                    className="group flex items-center justify-between"
                  >
                    <div className="flex items-center gap-2">
                      <Clock className="text-muted-foreground h-4 w-4" />
                      <span>{search}</span>
                    </div>
                    <button
                      onClick={(e) => removeRecentSearch(search, e)}
                      className="transition-opacity group-hover:opacity-100"
                    >
                      <X className="text-muted-foreground hover:text-foreground h-3 w-3" />
                    </button>
                  </ComboboxItem>
                ))}
              </ComboboxGroup>
            )}

            {showResults && (
              <ComboboxGroup>
                {loading ? (
                  <div className="flex items-center justify-center p-4">
                    <Loader2 className="h-4 w-4 animate-spin" />
                    <span className="text-muted-foreground ml-2 text-sm">
                      Searching...
                    </span>
                  </div>
                ) : results.length > 0 ? (
                  <>
                    <ComboboxLabel>Search Results</ComboboxLabel>
                    {results.map((item) => (
                      <ComboboxItem
                        key={item.id}
                        value={getSearchDisplayValue(item)}
                      >
                        <SearchItem item={item} />
                      </ComboboxItem>
                    ))}
                  </>
                ) : (
                  <ComboboxEmpty>
                    <div className="p-4 text-center">
                      <Search className="text-muted-foreground mx-auto mb-2 h-8 w-8" />
                      <p className="text-muted-foreground text-sm">
                        No results found for &quot;{query}&quot;
                      </p>
                    </div>
                  </ComboboxEmpty>
                )}
              </ComboboxGroup>
            )}

            {!query.trim() && !showRecent && !showTrending && (
              <div className="p-6 text-center">
                <Search className="text-muted-foreground mx-auto mb-2 h-8 w-8" />
                <p className="muted-foreground text-sm">
                  Start typing to search
                </p>
              </div>
            )}
          </ComboboxList>
        </ComboboxContent>
      </Combobox>
    </div>
  );
}

export default SearchComponent;

'use client';

import * as React from 'react';

import { Button } from '@/components/ui/button';
import {
  InputGroup,
  InputGroupAddon,
  InputGroupButton,
  InputGroupInput
} from '@/components/ui/input-group';
import { Combobox as ComboboxPrimitive } from '@base-ui/react';
import { ChevronDownIcon, XIcon, CheckIcon } from 'lucide-react';

import { cn } from '@/lib/utils';

const Combobox = ComboboxPrimitive.Root;

function ComboboxValue({ ...props }: ComboboxPrimitive.Value.Props) {
  return <ComboboxPrimitive.Value data-slot="combobox-value" {...props} />;
}

function ComboboxTrigger({
  className,
  children,
  ...props
}: ComboboxPrimitive.Trigger.Props) {
  return (
    <ComboboxPrimitive.Trigger
      data-slot="combobox-trigger"
      className={cn(
        "[&_svg:not([class*='size-')]:size-4 cursor-pointer",
        className
      )}
      {...props}
    >
      {children}
      <ChevronDownIcon className="text-muted-foreground pointer-events-none size-4" />
    </ComboboxPrimitive.Trigger>
  );
}

function ComboboxClear({ className, ...props }: ComboboxPrimitive.Clear.Props) {
  return (
    <ComboboxPrimitive.Clear
      data-slot="combobox-clear"
      className={cn('cursor-pointer', className)}
      {...props}
      render={
        <InputGroupButton variant="ghost" size="icon-xs">
          <XIcon className="pointer-events-none" />
        </InputGroupButton>
      }
    />
  );
}

function ComboboxInput({
  className,
  children,
  disabled = false,
  showTrigger = true,
  showClear = false,
  ...props
}: ComboboxPrimitive.Input.Props & {
  showTrigger?: boolean;
  showClear?: boolean;
}) {
  return (
    <InputGroup className={cn('w-auto', className)}>
      <ComboboxPrimitive.Input
        render={<InputGroupInput disabled={disabled} />}
        {...props}
      />
      <InputGroupAddon align="inline-end">
        {showTrigger && (
          <InputGroupButton
            size="icon-xs"
            variant="ghost"
            asChild
            data-slot="input-group-button"
            className="cursor-pointer group-has-data-[slot=combobox-clear]/input-group:hidden data-pressed:bg-transparent"
            disabled={disabled}
          >
            <ComboboxTrigger />
          </InputGroupButton>
        )}
        {showClear && <ComboboxClear disabled={disabled} />}
      </InputGroupAddon>
      {children}
    </InputGroup>
  );
}

function ComboboxContent({
  className,
  side = 'bottom',
  sideOffset = 6,
  align = 'start',
  alignOffset = 0,
  anchor,
  ...props
}: ComboboxPrimitive.Popup.Props &
  Pick<
    ComboboxPrimitive.Positioner.Props,
    'side' | 'align' | 'sideOffset' | 'alignOffset' | 'anchor'
  >) {
  return (
    <ComboboxPrimitive.Portal>
      <ComboboxPrimitive.Positioner
        side={side}
        sideOffset={sideOffset}
        align={align}
        alignOffset={alignOffset}
        anchor={anchor}
        className="isolate z-50"
      >
        <ComboboxPrimitive.Popup
          data-slot="combobox-content"
          data-chips={!!anchor}
          className={cn(
            'bg-popover text-popover-foreground data-open:animate-in data-closed:animate-out data-closed:fade-out-0 data-open:fade-in-0 data-closed:zoom-out-95 data-open:zoom-in-95 data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 ring-foreground/10 *:data-[slot=input-group]:bg-input/30 *:data-[slot=input-group]:border-input/30 data-[side=inline-start]:slide-in-from-right-2 data-[side=inline-end]:slide-in-from-left-2 group/combobox-content relative max-h-(--available-height) w-(--anchor-width) max-w-(--available-width) min-w-[calc(var(--anchor-width)+--spacing(7))] origin-(--transform-origin) overflow-hidden rounded-lg shadow-md ring-1 duration-100 data-[chips=true]:min-w-(--anchor-width) *:data-[slot=input-group]:m-1 *:data-[slot=input-group]:mb-0 *:data-[slot=input-group]:h-8 *:data-[slot=input-group]:shadow-none',
            className
          )}
          {...props}
        />
      </ComboboxPrimitive.Positioner>
    </ComboboxPrimitive.Portal>
  );
}

function ComboboxList({ className, ...props }: ComboboxPrimitive.List.Props) {
  return (
    <ComboboxPrimitive.List
      data-slot="combobox-list"
      className={cn(
        'no-scrollbar max-h-[min(calc(--spacing(72)---spacing(9)),calc(var(--available-height)---spacing(9)))] scroll-py-1 overflow-y-auto overscroll-contain p-1 data-empty:p-0',
        className
      )}
      {...props}
    />
  );
}

function ComboboxItem({
  className,
  children,
  ...props
}: ComboboxPrimitive.Item.Props) {
  return (
    <ComboboxPrimitive.Item
      data-slot="combobox-item"
      className={cn(
        "data-highlighted:bg-accent data-highlighted:text-accent-foreground not-data-[variant=destructive]:data-highlighted:**:text-accent-foreground relative flex w-full cursor-pointer items-center gap-2 rounded-md py-1 pr-8 pl-1.5 text-sm outline-hidden select-none data-disabled:pointer-events-none data-disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4",
        className
      )}
      {...props}
    >
      {children}
      <ComboboxPrimitive.ItemIndicator
        render={
          <span className="pointer-events-none absolute right-2 flex size-4 items-center justify-center">
            <CheckIcon className="pointer-events-none" />
          </span>
        }
      />
    </ComboboxPrimitive.Item>
  );
}

function ComboboxGroup({ className, ...props }: ComboboxPrimitive.Group.Props) {
  return (
    <ComboboxPrimitive.Group
      data-slot="combobox-group"
      className={cn(className)}
      {...props}
    />
  );
}

function ComboboxLabel({
  className,
  ...props
}: ComboboxPrimitive.GroupLabel.Props) {
  return (
    <ComboboxPrimitive.GroupLabel
      data-slot="combobox-label"
      className={cn('text-muted-foreground px-2 py-1.5 text-xs', className)}
      {...props}
    />
  );
}

function ComboboxCollection({ ...props }: ComboboxPrimitive.Collection.Props) {
  return (
    <ComboboxPrimitive.Collection data-slot="combobox-collection" {...props} />
  );
}

function ComboboxEmpty({ className, ...props }: ComboboxPrimitive.Empty.Props) {
  return (
    <ComboboxPrimitive.Empty
      data-slot="combobox-empty"
      className={cn(
        'text-muted-foreground hidden w-full justify-center py-2 text-center text-sm group-data-empty/combobox-content:flex',
        className
      )}
      {...props}
    />
  );
}

function ComboboxSeparator({
  className,
  ...props
}: ComboboxPrimitive.Separator.Props) {
  return (
    <ComboboxPrimitive.Separator
      data-slot="combobox-separator"
      className={cn('bg-border -mx-1 my-1 h-px', className)}
      {...props}
    />
  );
}

function ComboboxChips({
  className,
  ...props
}: React.ComponentPropsWithRef<typeof ComboboxPrimitive.Chips> &
  ComboboxPrimitive.Chips.Props) {
  return (
    <ComboboxPrimitive.Chips
      data-slot="combobox-chips"
      className={cn(
        'dark:bg-input/30 border-input focus-within:border-ring focus-within:ring-ring/50 has-aria-invalid:ring-destructive/20 dark:has-aria-invalid:ring-destructive/40 has-aria-invalid:border-destructive dark:has-aria-invalid:border-destructive/50 flex min-h-8 flex-wrap items-center gap-1 rounded-lg border bg-transparent bg-clip-padding px-2.5 py-1 text-sm transition-colors focus-within:ring-3 has-aria-invalid:ring-3 has-data-[slot=combobox-chip]:px-1',
        className
      )}
      {...props}
    />
  );
}

function ComboboxChip({
  className,
  children,
  showRemove = true,
  ...props
}: ComboboxPrimitive.Chip.Props & {
  showRemove?: boolean;
}) {
  return (
    <ComboboxPrimitive.Chip
      data-slot="combobox-chip"
      className={cn(
        'bg-muted text-foreground flex h-[calc(--spacing(5.25))] w-fit items-center justify-center gap-1 rounded-sm px-1.5 text-xs font-medium whitespace-nowrap has-disabled:pointer-events-none has-disabled:cursor-not-allowed has-disabled:opacity-50 has-data-[slot=combobox-chip-remove]:pr-0',
        className
      )}
      {...props}
    >
      {children}
      {showRemove && (
        <ComboboxPrimitive.ChipRemove
          className="-ml-1 cursor-pointer opacity-50 hover:opacity-100"
          data-slot="combobox-chip-remove"
          render={
            <Button variant="ghost" size="icon">
              <XIcon className="pointer-events-none" />
            </Button>
          }
        />
      )}
    </ComboboxPrimitive.Chip>
  );
}

function ComboboxChipsInput({
  className,
  ...props
}: ComboboxPrimitive.Input.Props) {
  return (
    <ComboboxPrimitive.Input
      data-slot="combobox-chip-input"
      className={cn('min-w-16 flex-1 outline-none', className)}
      {...props}
    />
  );
}

function useComboboxAnchor() {
  return React.useRef<HTMLDivElement | null>(null);
}

export {
  Combobox,
  ComboboxInput,
  ComboboxContent,
  ComboboxList,
  ComboboxItem,
  ComboboxGroup,
  ComboboxLabel,
  ComboboxCollection,
  ComboboxEmpty,
  ComboboxSeparator,
  ComboboxChips,
  ComboboxChip,
  ComboboxChipsInput,
  ComboboxTrigger,
  ComboboxValue,
  useComboboxAnchor
};

import { useState, useEffect } from 'react';

/**
 * A custom hook that debounces a value.
 *
 * @param value - The value to debounce
 * @param delay - The delay in milliseconds
 * @returns The debounced value
 */
export function useDebounce<T>(value: T, delay: number): T {
  const [debouncedValue, setDebouncedValue] = useState<T>(value);

  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    return () => {
      clearTimeout(handler);
    };
  }, [value, delay]);

  return debouncedValue;
}
